import hashlib
import json
from typing import Optional
import redis


class TenantCacheNamespace:
    """
    A per-tenant cache namespace for Claude prompt responses.
    Uses Redis with structured key namespacing to enforce tenant isolation.
    """

    def __init__(self, redis_client: redis.Redis, ttl_seconds: int = 3600):
        self.r = redis_client
        self.ttl = ttl_seconds

    def _build_key(
        self,
        tenant_id: str,
        feature_name: str,
        prompt_version: str,
        model_version: str,
        prompt_hash: str,
        user_id: Optional[str] = None
    ) -> str:
        parts = [
            f"tenant:{tenant_id}",
            f"feature:{feature_name}",
            f"pv:{prompt_version}",
            f"model:{model_version}",
            f"ph:{prompt_hash}"
        ]
        if user_id:
            parts.insert(1, f"user:{user_id}")
        return ":".join(parts)

    def _hash_prompt(self, messages: list, system: str) -> str:
        content = json.dumps({"system": system, "messages": messages}, sort_keys=True)
        return hashlib.sha256(content.encode()).hexdigest()[:20]

    def get(
        self, tenant_id, feature_name, prompt_version,
        model_version, messages, system, user_id=None
    ) -> Optional[dict]:
        ph = self._hash_prompt(messages, system)
        key = self._build_key(tenant_id, feature_name, prompt_version, model_version, ph, user_id)
        raw = self.r.get(key)
        if raw:
            return json.loads(raw)
        return None

    def set(
        self, tenant_id, feature_name, prompt_version,
        model_version, messages, system, response, user_id=None
    ) -> None:
        ph = self._hash_prompt(messages, system)
        key = self._build_key(tenant_id, feature_name, prompt_version, model_version, ph, user_id)
        self.r.setex(key, self.ttl, json.dumps(response))

    def invalidate_tenant(self, tenant_id: str) -> int:
        """Remove all cache entries for a tenant."""
        pattern = f"tenant:{tenant_id}:*"
        keys = self.r.keys(pattern)
        if keys:
            return self.r.delete(*keys)
        return 0

    def invalidate_prompt_version(
        self, tenant_id: str, feature_name: str, old_version: str
    ) -> int:
        """Invalidate stale entries when a prompt version is retired."""
        pattern = f"tenant:{tenant_id}:feature:{feature_name}:pv:{old_version}:*"
        keys = self.r.keys(pattern)
        if keys:
            return self.r.delete(*keys)
        return 0

# Before: prompt_version = 'v2.0' => key contains 'pv:v2.0'
# After:  prompt_version = 'v2.1' => key contains 'pv:v2.1'
# Old entries with 'pv:v2.0' are never matched again and die via TTL.

PROMPT_VERSIONS = {
    "chat":          "v2.1",
    "summarization": "v1.8",
    "extraction":    "v3.0"
}

def get_prompt_version(feature: str) -> str:
    return PROMPT_VERSIONS.get(feature, "v1.0")
